int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    const long long MOD = 1000000007LL;
    int n;
    std::cin >> n;
    std::vector<int> exp(n + 1, 0);
    for (int x = 2; x <= n; ++x) {
        int v = x;
        for (int p = 2; p * p <= v; ++p) {
            while (v % p == 0) {
                ++exp[p];
                v /= p;
            }
        }
        if (v > 1) ++exp[v];
    }
    long long ans = 1;
    for (int e : exp) {
        if (e) ans = ans * (e + 1) % MOD;
    }
    std::cout << ans << '\n';
    return 0;
}

