    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<long long> a(n), b(n), c(n);
    for (long long& x : a) std::cin >> x;
    for (long long& x : b) std::cin >> x;
    for (long long& x : c) std::cin >> x;
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());
    std::sort(c.begin(), c.end());

    long long ans = 0;
    for (long long x : b) {
        long long left = std::lower_bound(a.begin(), a.end(), x) - a.begin();
        long long right = c.end() - std::upper_bound(c.begin(), c.end(), x);
        ans += left * right;
    }
    std::cout << ans << '\n';
    return 0;
}

