#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<int> top(n), bottom(n);
    for (int& x : top) std::cin >> x;
    for (int& x : bottom) std::cin >> x;

    std::vector<int> pref(n + 1, 0), suff(n + 1, 0);
    for (int i = 0; i < n; ++i) pref[i + 1] = pref[i] + top[i];
    for (int i = n - 1; i >= 0; --i) suff[i] = suff[i + 1] + bottom[i];
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        ans = std::max(ans, pref[i + 1] + suff[i]);
    }
    std::cout << ans << '\n';
    return 0;
}
